class Solution {
public:
    string reverseParentheses(string s) {
        stack<string> st;
        for (char c : s) {
            if (c == '(') {
                st.push("");
            } else if (c == ')') {
                string temp = st.top();
                st.pop();
                string rev = temp;
                reverse(rev.begin(), rev.end());
                for (char c : rev) {
                    st.top() += c;
                }
            } else {
                st.top() += c;
            }
        }
        string res = "";
        while (!st.empty()) {
            res = st.top() + res;
            st.pop();
        }
        return res;
    }
};
```

